import React, { useState } from "react";
import List from "./List";
import "../../styles/components/dropdown.scss";
import { useClickAway } from "@uidotdev/usehooks";
import { __ } from "@wordpress/i18n";

function BackendDropdown({
  options = [],
  defaultValue,
  className,
  placeholder,
  onSelect,
}) {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);

  const ref = useClickAway(() => {
    setIsDropdownOpen(false);
  });
  const [selectedValue, setSelectedValue] = useState(defaultValue);

  const handleSelect = (value) => {
    setSelectedValue(value);
    if (onSelect) {
      onSelect(value);
    }
    setIsDropdownOpen(false);
  };

  const handleFocus = () => {
    if (options.length == 0) return;
    setIsDropdownOpen(true);
  };

  return (
    <div ref={ref} className={`dropdown ${className}`}>
      <div className="dropdown__container">
        <div onClick={handleFocus} className="dropdown-field">
          <fieldset className="dropdown__field-border" />
          <div className="dropdown__field-label dropdown__field-label--active">
            {options.length > 0 && selectedValue && <span>{placeholder}</span>}
          </div>
          <span
            className={`dropdown-field__selected-value ${
              !selectedValue ? "dropdown-field__selected-value--no-options" : ""
            }`}
          >
            {options.length === 0
              ? __("No options", "hostinger-affiliate-plugin")
              : selectedValue?.label || placeholder}
          </span>
          {options.length > 0 && (
            <span
              className={`dropdown__arrow-icon ${
                isDropdownOpen ? "dropdown__arrow-icon--active" : ""
              }`}
            >
              <svg
                part="svg"
                xmlns="http://www.w3.org/2000/svg"
                aria-hidden="true"
                aria-labelledby="icon-arrow-drop-down"
                focusable="false"
                style={{ width: '24px', height: '24px' }} // Correct style usage
                viewBox="0 0 24 24"

              >
                <g>
                  <path
                    fillRule="evenodd"
                    clipRule="evenodd"
                    fill="#727586"
                    d="M7 10L12 15L17 10H7Z"
                  ></path>
                </g>
              </svg>
            </span>
          )}
        </div>

        {isDropdownOpen && options.length > 0 && (
          <List
            ref={ref}
            className="dropdown__list"
            options={options}
            itemsPerList={5}
            onSelect={handleSelect}
          />
        )}
      </div>
    </div>
  );
}

export default BackendDropdown;
