import React, { useState } from 'react';

import { __ } from '@wordpress/i18n';

import { TextControl } from '@wordpress/components';

import { ToastContainer, toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import HostingerTooltip from "./ui/tooltip/HostingerTooltip";

const ProductSelector = (props) => {

    const [loading, setLoading] = useState(false);

    let content = [];

    const prepareErrorString = (errors) => {
        let error_string = __('There was an error validating product ids: ', 'hostinger-affiliate-plugin');

        for (let key in errors) {
            if (errors.hasOwnProperty(key)) {
                error_string += errors[key] + ' ';
            }
        }

        return error_string;
    }

    const addProduct = (e) => {
        if(props.validateAsins(props.attributes.asin)) {
            setLoading(true);

            fetch(hst_affiliate_data.rest_base_url + 'hostinger-affiliate-plugin/v1/validate-items', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-WP-Nonce': hst_affiliate_data.nonce,
                    'X-Hpanel-Domain': hst_affiliate_data.block['domain_settings']['domain'],
                    'Cache-Control': 'no-cache'
                },
                body: JSON.stringify({
                    items: props.attributes.asin,
                    layout: props.attributes.display_type
                })
            })
                .then((response) => {
                    return response.json();
                })
                .then((data) => {
                    setLoading(false)
                    if(data.data.errors) {
                        toast.error(prepareErrorString(data.data.errors));
                    } else if(data.data.status >= 500) {
                        toast.error( __('There was fatal server error while processing your request.', 'hostinger-affiliate-plugin') );
                    } else {
                        props.appendItemData(data.items);
                        props.setAttributes( {
                            asin_manual: props.attributes.asin,
                            ready: true
                        } );
                    }
                });

        } else {
            toast.error( __('ASIN validation failed. Please check entered product ASIN!', 'hostinger-affiliate-plugin') );
        }
    }

    // Don't have anything selected
    if( props.attributes.product_selector == '' ) {
        content.push(
            <>
                <div className="hostinger-block-product-selector__help-text">
                    { __('How do you want to add the product?', 'hostinger-affiliate-plugin') }
                </div>
                <div className="hostinger-block-product-selector__buttons-wrap">
                    <div className="hostinger-block-product-selector__buttons-item hostinger-block-product-selector__buttons-item--is-for-button">
                        <HostingerTooltip
                            content={ hst_affiliate_data.translations.asin_tooltip }
                            styling = {
                                {
                                    wrapper: {
                                        width: '100%'
                                    }
                                }
                            }
                        >
                            <button
                                type="button"
                                className="hostinger-block-button hostinger-block-button--is-big hostinger-block-button--is-primary-outline"
                                onClick={ () => props.setAttributes({ product_selector: 'type_asin' }) }
                            >
                                <div className="hostinger-block-button__icon">
                                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                        <g id="icon-store">
                                            <path d="M5.0002 4H19.0002C19.2835 4 19.521 4.09583 19.7127 4.2875C19.9044 4.47917 20.0002 4.71667 20.0002 5C20.0002 5.28333 19.9044 5.52083 19.7127 5.7125C19.521 5.90417 19.2835 6 19.0002 6H5.0002C4.71686 6 4.47936 5.90417 4.2877 5.7125C4.09603 5.52083 4.0002 5.28333 4.0002 5C4.0002 4.71667 4.09603 4.47917 4.2877 4.2875C4.47936 4.09583 4.71686 4 5.0002 4ZM5.0002 20C4.71686 20 4.47936 19.9042 4.2877 19.7125C4.09603 19.5208 4.0002 19.2833 4.0002 19V14H3.8252C3.50853 14 3.2502 13.8792 3.0502 13.6375C2.8502 13.3958 2.78353 13.1167 2.8502 12.8L3.8502 7.8C3.9002 7.56667 4.01686 7.375 4.2002 7.225C4.38353 7.075 4.59186 7 4.8252 7H19.1752C19.4085 7 19.6169 7.075 19.8002 7.225C19.9835 7.375 20.1002 7.56667 20.1502 7.8L21.1502 12.8C21.2169 13.1167 21.1502 13.3958 20.9502 13.6375C20.7502 13.8792 20.4919 14 20.1752 14H20.0002V19C20.0002 19.2833 19.9044 19.5208 19.7127 19.7125C19.521 19.9042 19.2835 20 19.0002 20C18.7169 20 18.4794 19.9042 18.2877 19.7125C18.096 19.5208 18.0002 19.2833 18.0002 19V14H14.0002V19C14.0002 19.2833 13.9044 19.5208 13.7127 19.7125C13.521 19.9042 13.2835 20 13.0002 20H5.0002ZM6.0002 18H12.0002V14H6.0002V18ZM5.0502 12H18.9502L18.3502 9H5.6502L5.0502 12Z" fill="#673DE6"/>
                                        </g>
                                    </svg>
                                </div>
                                { __( 'Type ASIN (Product ID)', 'hostinger-affiliate-plugin' ) }
                            </button>
                        </HostingerTooltip>
                    </div>
                    <div className="hostinger-block-product-selector__buttons-item hostinger-block-product-selector__buttons-item--is-for-seperator">
                        { __( 'or', 'hostinger-affiliate-plugin' ) }
                    </div>
                    <div className="hostinger-block-product-selector__buttons-item hostinger-block-product-selector__buttons-item--is-for-button">
                        <button
                            type="button"
                            className={ `hostinger-block-button hostinger-block-button--is-big hostinger-block-button--is-primary-outline hostinger-affiliate__open-search-modal ${props.attributes.display_type == "single_product_card" ? "hostinger-affiliate__open-search-modal--is-single" : "hostinger-affiliate__open-search-modal--is-multiple"}` }
                        >
                            <div className="hostinger-block-button__icon">
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                    <g id="icon-search">
                                        <path d="M9.5 16C7.68333 16 6.14583 15.3708 4.8875 14.1125C3.62917 12.8542 3 11.3167 3 9.5C3 7.68333 3.62917 6.14583 4.8875 4.8875C6.14583 3.62917 7.68333 3 9.5 3C11.3167 3 12.8542 3.62917 14.1125 4.8875C15.3708 6.14583 16 7.68333 16 9.5C16 10.2333 15.8833 10.925 15.65 11.575C15.4167 12.225 15.1 12.8 14.7 13.3L20.3 18.9C20.4833 19.0833 20.575 19.3167 20.575 19.6C20.575 19.8833 20.4833 20.1167 20.3 20.3C20.1167 20.4833 19.8833 20.575 19.6 20.575C19.3167 20.575 19.0833 20.4833 18.9 20.3L13.3 14.7C12.8 15.1 12.225 15.4167 11.575 15.65C10.925 15.8833 10.2333 16 9.5 16ZM9.5 14C10.75 14 11.8125 13.5625 12.6875 12.6875C13.5625 11.8125 14 10.75 14 9.5C14 8.25 13.5625 7.1875 12.6875 6.3125C11.8125 5.4375 10.75 5 9.5 5C8.25 5 7.1875 5.4375 6.3125 6.3125C5.4375 7.1875 5 8.25 5 9.5C5 10.75 5.4375 11.8125 6.3125 12.6875C7.1875 13.5625 8.25 14 9.5 14Z" fill="#673DE6"/>
                                    </g>
                                </svg>
                            </div>
                            { __( 'Search for the product in Amazon', 'hostinger-affiliate-plugin' ) }
                        </button>
                    </div>
                </div>
            </>
        )
    }

    if( props.attributes.product_selector == 'type_asin' ) {

        content.push(
            <>
                <div
                    className="hostinger-block-product-selector__back-text-wrap"
                    onClick={ () => props.setAttributes({ product_selector: '' }) }
                    onKeyPress={ () => props.setAttributes({ product_selector: '' }) }
                    role="button"
                >
                    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <g id="ic_arrow_forward">
                            <path d="M16.6673 9.16668H6.52565L11.184 4.50834L10.0007 3.33334L3.33398 10L10.0007 16.6667L11.1757 15.4917L6.52565 10.8333H16.6673V9.16668Z" fill="#673DE6"/>
                        </g>
                    </svg>
                    <div className="hostinger-block-product-selector__back-text">
                        { __('How do you want to add the product?', 'hostinger-affiliate-plugin') }
                    </div>
                </div>
                <div className="hostinger-block-product-selector__help-text"
                     /* translators: %s: ASIN helper page URL */
                     dangerouslySetInnerHTML={{__html: sprintf(__('Copy-paste Amazon product ASIN. <a href="%s" target="_blank">Where to find it?</a>', 'hostinger-affiliate-plugin'), 'https://developer.amazon.com/docs/mobile-associates/mas-finding-product-id.html#:~:text=You%20can%20find%20the%20ASIN,URL%20of%20the%20product%20page.') }}
                >
                </div>
                <TextControl
                    ref= { input => input && '' === props.attributes.asin && input.focus() }
                    key = "hostinger-block-product-selector__product-asin-field"
                    className = "hostinger-block-product-selector__product-asin-field"
                    value = { props.attributes.asin }
                    placeholder = { __( 'Enter ASIN here', 'hostinger-affiliate-plugin') }
                    onChange = { (value) => props.setAttributes( { asin: value } ) }
                    disabled={ loading }
                />
                <div className="hostinger-block-product-selector__snackbar">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                        <path d="M12 2C6.477 2 2 6.477 2 12C2 17.523 6.477 22 12 22C17.523 22 22 17.523 22 12C22 6.477 17.523 2 12 2ZM13 17H11V11H13V17ZM13 9H11V7H13V9Z" fill="#727586"/>
                    </svg>
                    { __('Don’t worry. You can edit the layout and product in the Block configuration in the right sidebar anytime.', 'hostinger-affiliate-plugin') }
                </div>
                <div className="hostinger-block-product-selector__add-product-wrap">
                    <button
                        type="button"
                        onClick={ addProduct }
                        disabled={ !props.attributes.asin || loading }
                        className="hostinger-block-button hostinger-block-button--is-normal hostinger-block-button--is-primary">
                        { __('Add product', 'hostinger-affiliate-plugin') }
                    </button>
                </div>
            </>
        )

    }

    return (
        <>
            <div className="hostinger-block-product-selector">
                <div className="hostinger-block-product-selector__divider"></div>
                { content }
            </div>
            <ToastContainer />
        </>
    );
}
export default ProductSelector
