import React from "react";
import ListItem from "./ListItem";
import "../../styles/components/list.scss";
import { __ } from "@wordpress/i18n";

function List({ options, noOptions, className, onSelect }) {
  return (
    <ul className={`list text-body-2 ${className}`}>
      {noOptions ? (
        <ListItem
          className="list--no-match"
          option={{
            label: __( 'No matching options', 'hostinger-affiliate-plugin' ),
            value: "no-option",
          }}
        />
      ) : (
        options.map((option) => (
          <ListItem
            key={option.value}
            option={option}
            isActive={option.selected}
            onSelect={() => onSelect(option)}
          />
        ))
      )}
    </ul>
  );
}

export default List;
