import React from "react";
import { __ } from "@wordpress/i18n";

const DisplayTypeSelector = ({ entries, changeDisplayType, buttonClass }) => {

    return (
        <div className="hostinger-block-display-selector__templates">
            {Object.entries(entries).map((type, index) => {
                return (
                    <div
                        key="index"
                        className={`hostinger-block-display-selector__template-item ${
                            type[1].disabled
                                ? "hostinger-block-display-selector__template-item--is-disabled"
                                : ""
                        }`}
                    >
                        <div className="hostinger-block-display-selector__template-image">
                            <img
                                src={
                                    hst_affiliate_data.plugin_url +
                                    "assets/img/" +
                                    type[1].image
                                }
                                alt=""
                            />
                        </div>
                        <div className="hostinger-block-display-selector__template-title">
                            {type[1].label}
                        </div>
                        <div className="hostinger-block-display-selector__template-subtitle">
                            {type[1].description}
                        </div>
                        <div className="hostinger-block-display-selector__template-button-wrap">
                            <button
                                onClick={() => changeDisplayType(type[1].value)}
                                className={`hostinger-block-button hostinger-block-button--is-small ${ buttonClass }`}
                                type="button"
                            >
                                {type[1].disabled
                                    ? __("Coming soon", "hostinger-affiliate-plugin")
                                    : __("Select", "hostinger-affiliate-plugin")}
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

export default DisplayTypeSelector;
